//! Build script to auto-generate binary wrappers for guest-lib programs.
//!
//! This scans the guest-lib/examples/ directory and generates a binary
//! wrapper for each example. Manual binaries (opcode tests) are preserved.

use std::fs;
use std::path::Path;

/// Marker comment to identify auto-generated files.
const AUTO_GEN_MARKER: &str = "// AUTO-GENERATED by guest-bin/build.rs - DO NOT EDIT";

fn main() {
    let examples_dir = Path::new("../guest-lib/examples");
    let bin_dir = Path::new("src/bin");

    // Ensure bin directory exists
    fs::create_dir_all(bin_dir).expect("Failed to create src/bin directory");

    // Tell Cargo to rerun if examples directory changes
    println!("cargo:rerun-if-changed=../guest-lib/examples");

    // Emit linker script path using absolute path from CARGO_MANIFEST_DIR.
    // This allows external projects to use guest-bin as a git dependency.
    let manifest_dir = std::env::var("CARGO_MANIFEST_DIR").unwrap();
    let linker_path = Path::new(&manifest_dir).join("linker.ld");
    println!("cargo:rustc-link-arg=-T{}", linker_path.display());
    println!("cargo:rerun-if-changed=linker.ld");
    println!("cargo:rerun-if-env-changed=STARKV_HEAP_SIZE");

    if let Ok(heap_size) = std::env::var("STARKV_HEAP_SIZE")
        && let Some(size) = parse_heap_size(&heap_size)
    {
        println!("cargo:rustc-link-arg=--defsym=__heap_size={size}");
    }

    // Scan for example files
    let entries = match fs::read_dir(examples_dir) {
        Ok(entries) => entries,
        Err(_) => {
            // Examples may not exist yet on first build
            return;
        }
    };

    for entry in entries.flatten() {
        let path = entry.path();

        // Skip non-rust files
        if path.extension().is_some_and(|ext| ext == "rs") {
            let file_name = path.file_stem().unwrap().to_str().unwrap();

            let bin_content = if file_name == "revm_smoke" {
                format!(
                    r#"{AUTO_GEN_MARKER}
#![no_std]
#![no_main]

#[cfg(feature = "revm")]
guest_bin::guest_main!(guest_lib::programs::revm_smoke::test_call());

#[cfg(not(feature = "revm"))]
guest_bin::guest_main!(0u8);
"#
                )
            } else {
                // Generate binary wrapper that calls test_call from the programs module
                format!(
                    r#"{AUTO_GEN_MARKER}
#![no_std]
#![no_main]

guest_bin::guest_main!(guest_lib::programs::{file_name}::test_call());
"#
                )
            };

            let bin_path = bin_dir.join(format!("{file_name}.rs"));

            // Check if file exists and whether it's auto-generated or manual
            let should_write = match fs::read_to_string(&bin_path) {
                Ok(existing) => {
                    // Only overwrite if it's auto-generated (has marker) and content changed
                    existing.starts_with(AUTO_GEN_MARKER) && existing != bin_content
                }
                Err(_) => true, // File doesn't exist, create it
            };

            if should_write {
                fs::write(&bin_path, &bin_content)
                    .unwrap_or_else(|e| panic!("Failed to write {}: {}", bin_path.display(), e));
            }
        }
    }
}

fn parse_heap_size(value: &str) -> Option<u64> {
    let trimmed = value.trim();
    if let Some(hex) = trimmed.strip_prefix("0x") {
        u64::from_str_radix(hex, 16).ok()
    } else {
        trimmed.parse().ok()
    }
}
